<script lang="ts">
  import { audioVisuals, playback } from '../../lib/stores/playback'
  import { settings as settingsStore } from '../../lib/stores/settings'

  $: ({ audioLevel } = $audioVisuals)
  $: ({ isPlaying } = $playback)
  $: ({ performanceProfile } = $settingsStore)

  let mood = 0
  let smoothedLevel = 0
  let pulse = 0

  $: {
    const energyFactor = Math.min(audioLevel * 2, 1)
    const targetMood = isPlaying ? 0.2 + energyFactor * 0.6 : 0
    mood += (targetMood - mood) * 0.1

    smoothedLevel += (audioLevel - smoothedLevel) * 0.1
    pulse = isPlaying ? 1 + Math.sin(Date.now() / 1000) * 0.05 + smoothedLevel * 0.2 : 1
  }

  $: yOffset = mood * 20

  $: color1 = `rgba(var(--accent-primary-rgb), ${0.08 + smoothedLevel * 0.1})`
  $: color2 = `rgba(var(--accent-primary-rgb), ${0.04 + smoothedLevel * 0.05})`
</script>

<div
  class="fixed inset-0 pointer-events-none overflow-hidden z-0 bg-[var(--bg-app)] transition-colors duration-1000"
>
  {#if performanceProfile === 'epic'}
    <!-- Abstract Mood Orbs (REMOVED FOR PERFORMANCE) -->
    <!--
    <div
      class="absolute top-[-15%] left-[-15%] w-[80%] h-[80%] rounded-full blur-[64px] transition-all duration-1000"
      style="background: radial-gradient(circle, {color1} 0%, transparent 70%); transform: scale({pulse}) translateY({yOffset}%);"
    ></div>

    <div
      class="absolute bottom-[-25%] right-[-15%] w-[90%] h-[90%] rounded-full blur-[80px] transition-all duration-1000"
      style="background: radial-gradient(circle, {color2} 0%, transparent 70%); transform: scale({pulse *
        1.1}) translateY({-yOffset}%);"
    ></div>
    -->

    <!-- Subtle Grain / Noise Overlay (Global alternative) -->
    <div
      class="absolute inset-0 opacity-[0.03] mix-blend-overlay pointer-events-none grain-overlay"
    ></div>
  {/if}

  <!-- Deep Ambience (Optimized) -->
  <div
    class="absolute inset-0 opacity-10"
    style="background: radial-gradient(circle at 50% 50%, rgba(var(--accent-primary-rgb), 0.1) 0%, transparent 100%);"
  ></div>
</div>

<style>
  .grain-overlay {
    /* Using a simpler, static repeating noise pattern instead of dynamic feTurbulence */
    background-image: url("data:image/png;base64,");
  }
</style>
